// app/admin/catalog/page.tsx
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/products';

/**
 * This page must be dynamic so product data is fetched per-request
 * (served from the shared cache) rather than embedded in the static
 * HTML at build time.  This allows `revalidateTag("products")` to take
 * effect immediately across all views that share the cache tag.
 */
export const dynamic = 'force-dynamic';

/**
 * Simulates a long-running catalog sync job (e.g. fetching updated pricing,
 * inventory, and availability from an upstream ERP/PIM system).
 *
 * In production this would enqueue a background worker, call an external API,
 * or write to a job table.  The key design property is that the *caller* does
 * not await this promise — the page responds immediately and the cache is
 * invalidated only after the sync finishes.
 */
async function syncJob(): Promise<void> {
  console.log('[Catalog Sync] background sync started');

  // Simulate upstream data fetch — thousands of SKUs
  // In production: fetchDeltaFromERP(), writeToStaging(), etc.
  await new Promise<void>((resolve) => setTimeout(() => resolve(), 5_000));

  console.log('[Catalog Sync] sync complete, revalidating cache tag "products"');

  // Invalidate every view that depends on the "products" cache tag.
  // The next request to any such view will re-execute its data function
  // and serve fresh data.
  revalidateTag('products', {});
}

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  /**
   * Inline Server Action — no client JavaScript required for the form submit.
   *
   * Fires the background sync and returns immediately so the admin can
   * continue working.  The product list may show stale data for a few
   * seconds until `syncJob` finishes and invalidates the `"products"` tag.
   */
  async function syncCatalog(): Promise<void> {
    'use server';

    console.log('[Catalog Sync] trigger received');

    // Fire-and-forget: the action returns immediately; the cache is
    // invalidated only *after* the sync completes.
    syncJob().catch((err) => {
      console.error('[Catalog Sync] background job failed', err);
    });
  }

  return (
    <div className="catalog-page">
      <header className="catalog-header">
        <h1>Product Catalog</h1>
        <form action={syncCatalog}>
          <button type="submit" className="sync-btn">
            Sync Latest Catalog
          </button>
        </form>
      </header>

      {products.length === 0 ? (
        <p className="empty-state">No products found.</p>
      ) : (
        <table className="product-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Price</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td>{product.id}</td>
                <td>{product.name}</td>
                <td>${product.price.toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
